-- Get a Redis connection
local function get_redis_connection()
    local red = redis:new()
    red:set_timeout(REDIS_TIMEOUT)

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        ngx.log(ngx.ERR, "Failed to connect to Redis: ", err)
        return nil, err
    end

    if REDIS_PASSWORD then
        local res, err = red:auth(REDIS_PASSWORD)
        if not res then
            ngx.log(ngx.ERR, "Failed to authenticate with Redis: ", err)
            return nil, err
        end
    end

    return red, nil
end

-- Return redis connection to the pool
local function release_redis_connection(red)
    if not red then return end
    local ok, err = red:set_keepalive(10000, 100)
    if not ok then
        ngx.log(ngx.WARN, "Failed to set Redis keepalive: ", err)
    end
end

-- Compile and cache a plugin function from code string
local function compile_plugin(plugin_name, code)
    if not code or code == "" then
        return nil, "Empty plugin code for: " .. (plugin_name or "unknown")
    end

    local load_fn = load or loadstring
    local chunk, err = load_fn(code, "plugin:" .. plugin_name)
    if not chunk then
        return nil, "Failed to compile plugin '" .. plugin_name .. "': " .. (err or "unknown error")
    end

    -- Apply sandbox
    local sandbox = create_sandbox_env()
    if setfenv then
        -- Lua 5.1 / LuaJIT
        setfenv(chunk, sandbox)
    else
        -- Lua 5.2+ the sandbox must be done via load's env parameter
        chunk, err = load(code, "plugin:" .. plugin_name, "t", sandbox)
        if not chunk then
            return nil, "Failed to compile plugin with sandbox '" .. plugin_name .. "': " .. (err or "unknown error")
        end
    end

    -- Execute the chunk to get the plugin table/function
    local ok, plugin_obj = pcall(chunk)
    if not ok then
        return nil, "Failed to execute plugin '" .. plugin_name .. "': " .. tostring(plugin_obj)
    end

    return plugin_obj, nil
end

-- Load plugin code from Redis
function _M.load_plugin_from_redis(plugin_name)
    if not plugin_name or plugin_name == "" then
        return nil, "Plugin name is required"
    end

    -- Check local cache first
    local cached_code = plugin_cache and plugin_cache:get(plugin_name)
    if cached_code then
        ngx.log(ngx.DEBUG, "Plugin '", plugin_name, "' loaded from cache")
        return compile_plugin(plugin_name, cached_code)
    end

    -- Fetch from Redis
    local red, err = get_redis_connection()
    if not red then
        return nil, "Redis connection failed: " .. (err or "unknown")
    end

    local redis_key = REDIS_PLUGIN_PREFIX .. plugin_name
    local code, err = red:get(redis_key)
    release_redis_connection(red)

    if not code or code == ngx.null then
        return nil, "Plugin '" .. plugin_name .. "' not found in Redis"
    end

    -- Cache the code
    if plugin_cache then
        local ok, err = plugin_cache:set(plugin_name, code, CACHE_TTL)
        if not ok then
            ngx.log(ngx.WARN, "Failed to cache plugin '", plugin_name, "': ", err)
        end
    end

    return compile_plugin(plugin_name, code)
end

-- Load plugin code from HTTP header
function _M.load_plugin_from_header(header_name)
    header_name = header_name or "X-Gateway-Plugin-Code"

    local code = ngx.req.get_headers()[header_name]
    if not code then
        return nil, "No plugin code found in header: " .. header_name
    end

    -- Decode if base64 encoded
    local decoded = ngx.decode_base64(code)
    if decoded then
        code = decoded
    end

    local plugin_name = ngx.req.get_headers()["X-Gateway-Plugin-Name"] or "header_plugin"
    return compile_plugin(plugin_name, code)
end

-- Store a plugin in Redis
function _M.store_plugin_in_redis(plugin_name, code)
    if not plugin_name or not code then
        return nil, "Plugin name and code are required"
    end

    local red, err = get_redis_connection()
    if not red then
        return nil, "Redis connection failed: " .. (err or "unknown")
    end

    local redis_key = REDIS_PLUGIN_PREFIX .. plugin_name
    local ok, err = red:set(redis_key, code)
    release_redis_connection(red)

    if not ok then
        return nil, "Failed to store plugin: " .. (err or "unknown")
    end

    -- Invalidate cache
    if plugin_cache then
        plugin_cache:delete(plugin_name)
    end

    ngx.log(ngx.INFO, "Plugin '", plugin_name, "' stored in Redis")
    return true, nil
end

-- Delete a plugin from Redis
function _M.delete_plugin_from_redis(plugin_name)
