-- List all plugins in Redis
function _M.list_plugins()
    local red, err = get_redis_connection()
    if not red then
        return nil, "Redis connection failed: " .. (err or "unknown")
    end

    local keys, err = red:keys(REDIS_PLUGIN_PREFIX .. "*")
    release_redis_connection(red)

    if not keys then
        return nil, "Failed to list plugins: " .. (err or "unknown")
    end

    local plugins = {}
    local prefix_len = #REDIS_PLUGIN_PREFIX
    for _, key in ipairs(keys) do
        local name = string.sub(key, prefix_len + 1)
        table.insert(plugins, name)
    end

    return plugins, nil
end

-- Execute a plugin by name with given context
function _M.execute_plugin(plugin_name, ctx)
    local plugin_obj, err = _M.load_plugin_from_redis(plugin_name)
    if not plugin_obj then
        return nil, err
    end

    ctx = ctx or {}

    -- Plugin can be a function or a table with an execute/handler method
    if type(plugin_obj) == "function" then
        local ok, result = pcall(plugin_obj, ctx)
        if not ok then
            return nil, "Plugin execution error: " .. tostring(result)
        end
        return result, nil
    elseif type(plugin_obj) == "table" then
        local handler = plugin_obj.execute or plugin_obj.handler or plugin_obj.run
        if handler and type(handler) == "function" then
            local ok, result = pcall(handler, plugin_obj, ctx)
            if not ok then
                return nil, "Plugin execution error: " .. tostring(result)
            end
            return result, nil
        else
            return nil, "Plugin table has no execute/handler/run method"
        end
    else
        return nil, "Plugin must return a function or table, got: " .. type(plugin_obj)
    end
end

-- Execute a chain of plugins in sequence
function _M.execute_plugin_chain(plugin_names, ctx)
    ctx = ctx or {}
    local results = {}

    for _, name in ipairs(plugin_names) do
        local result, err = _M.execute_plugin(name, ctx)
        if err then
            ngx.log(ngx.ERR, "Plugin chain error at '", name, "': ", err)
            -- Check if plugin set abort flag
            if ctx.abort then
                return results, "Chain aborted at plugin '" .. name .. "': " .. err
            end
        end
        table.insert(results, {
            plugin = name,
            result = result,
            error = err
        })

        -- Allow plugins to stop the chain
        if ctx.stop_chain then
            ngx.log(ngx.INFO, "Plugin chain stopped by '", name, "'")
            break
        end
    end

    return results, nil
end

-- Invalidate cached plugin
function _M.invalidate_cache(plugin_name)
    if plugin_cache then
        if plugin_name then
            plugin_cache:delete(plugin_name)
        else
            plugin_cache:flush_all()
            plugin_cache:flush_expired()
        end
    end
    return true
end

-- Main request handler for plugin management API
function _M.handle_admin_api()
    local method = ngx.req.get_method()
    local uri = ngx.var.uri
    local plugin_name = string.match(uri, "/plugins/([%w_%-%.]+)$")

    ngx.header["Content-Type"] = "application/json"

    -- GET /plugins - list all plugins
    if method == "GET" and not plugin_name then
        local plugins, err = _M.list_plugins()
        if not plugins then
            ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
            ngx.say(cjson.encode({ error = err }))
            return
        end
        ngx.say(cjson.encode({ plugins = plugins }))
        return
    end

    -- GET /plugins/:name - get plugin code
    if method == "GET" and plugin_name then
        local red, err = get_redis_connection()
        if not red then
            ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
            ngx.say(cjson.encode({ error = err }))
            return
        end

        local code, err = red:get(REDIS_PLUGIN_PREFIX .. plugin_name)
        release_redis_connection(red)

        if not code or code == ngx.null then
            ngx.status = ngx.HTTP_NOT_FOUND
            ngx.say(cjson.encode({ error = "Plugin not found" }))
            return
        end

        ngx.say(cjson.encode({ name = plugin_name, code = code }))
        return
    end

    -- PUT /plugins/:name - create/update plugin
    if method == "PUT" and plugin_name then
        ngx.req.read_body()
        local body = ngx.req.get_body_data()
        if not body then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = "Request body is required" }))
            return
        end

        local data = cjson.decode(body)
        local code = data and data.code
        if not code then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = "code field is required" }))
            return
        end

        -- Validate the code compiles
        local _, err = compile_plugin(plugin_name, code)
        if err then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = "Invalid plugin code: " .. err }))
            return
        end

        local ok, err = _M.store_plugin_in_redis(plugin_name, code)
        if not ok then
            ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
            ngx.say(cjson.encode({ error = err }))
            return
        end

        ngx.status = ngx.HTTP_OK
        ngx.say(cjson.encode({ message = "Plugin stored", name = plugin_name }))
        return
    end

    -- DELETE /plugins/:name - delete plugin
    if method == "DELETE" and plugin_name then
        local ok, err = _M.delete_plugin_from_redis(plugin_name)
        if not ok then
            ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
            ngx.say(cjson.encode({ error = err }))
            return
        end

        ngx.say(cjson.encode({ message = "Plugin deleted", name = plugin_name }))
        return
    end

    -- POST /plugins/:name/execute - execute a plugin
    if method == "POST" and string.match(uri, "/plugins/([%w_%-%.]+)/execute$") then
        plugin_name = string.match(uri, "/plugins/([%w_%-%.]+)/execute$")
        ngx.req.read_body()
        local body = ngx.req.get_body_data()
        local ctx = {}
        if body then
            ctx = cjson.decode(body) or {}
        end

        local result, err = _M.execute_plugin(plugin_name, ctx)
        if err then
            ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
            ngx.say(cjson.encode({ error = err }))
            return
        end

        ngx.say(cjson.encode({ result = result }))
        return
    end

    -- POST /plugins/cache/invalidate - clear cache
    if method == "POST" and string.match(uri, "/plugins/cache/invalidate$") then
        ngx.req.read_body()
        local body = ngx.req.get_body_data()
        local data = body and cjson.decode(body)
        local target_name = data and data.name

        _M.invalidate_cache(target_name)
        ngx.say(cjson.encode({
            message = target_name and ("Cache invalidated for: " .. target_name) or "All cache invalidated"
        }))
        return
    end

    ngx.status = ngx.HTTP_NOT_FOUND
    ngx.say(cjson.encode({ error = "Not found" }))
end

-- Access phase handler: runs configured plugin chain
function _M.access_phase_handler()
    local plugin_chain_header = ngx.req.get_headers()["X-Gateway-Plugins"]
    local plugin_names = {}

    if plugin_chain_header then
        -- Parse comma-separated plugin names from header
        for name in string.gmatch(plugin_chain_header, "([%w_%-%.]+)") do
            table.insert(plugin_names, name)
        end
    end

    -- Also check for inline plugin code in header
    local inline_code = ngx.req.get_headers()["X-Gateway-Plugin-Code"]
    if inline_code then
        local plugin_obj, err = _M.load_plugin_from_header("X-Gateway-Plugin-Code")
        if plugin_obj then
            local ctx = {
                method = ngx.req.get_method(),
                uri = ngx.var.uri,
                args = ngx.req.get_uri_args(),
                headers = ngx.req.get_headers(),
            }

            if type(plugin_obj) == "function" then
                local ok, result = pcall(plugin_obj, ctx)
                if not ok then
                    ngx.log(ngx.ERR, "Inline plugin error: ", tostring(result))
                end
            elseif type(plugin_obj) == "table" then
                local handler = plugin_obj.execute or plugin_obj.handler or plugin_obj.run
                if handler then
                    local ok, result = pcall(handler, plugin_obj, ctx)
                    if not ok then
                        ngx.log(ngx.ERR, "Inline plugin error: ", tostring(result))
                    end
                end
            end
        else
            ngx.log(ngx.ERR, "Failed to load inline plugin: ", err)
        end
    end

    -- Execute plugin chain from Redis
    if #plugin_names > 0 then
        local ctx = {
            method = ngx.req.get_method(),
            uri = ngx.var.uri,
            args = ngx.req.get_uri_args(),
            headers = ngx.req.get_headers(),
            phase = "access",
        }

        local results, err = _M.execute_plugin_chain(plugin_names, ctx)
        if err then
            ngx.log(ngx.ERR, "Plugin chain error: ", err)
        end

        -- Store results in ngx.ctx for later phases
        ngx.ctx.plugin_results = results

        -- Check if any plugin set response status
        if ctx.response_status then
            ngx.status = ctx.response_status
            if ctx.response_body then
                ngx.header["Content-Type"] = ctx.response_content_type or "application/json"
                ngx.say(ctx.response_body)
            end
            ngx.exit(ctx.response_status)
        end
    end
end

-- Header filter phase handler
function _M.header_filter_phase_handler()
    local plugin_chain_header = ngx.req.get_headers()["X-Gateway-Header-Filter-Plugins"]
    if not plugin_chain_header then
        return
    end

    local plugin_names = {}
    for name in string.gmatch(plugin_chain_header, "([%w_%-%.]+)") do
        table.insert(plugin_names, name)
    end

    if #plugin_names > 0 then
        local ctx = {
            method = ngx.req.get_method(),
            uri = ngx.var.uri,
            status = ngx.status,
            phase = "header_filter",
            upstream_headers = ngx.resp and ngx.resp.get_headers and ngx.resp.get_headers() or {},
        }

        _M.execute_plugin_chain(plugin_names, ctx)
    end
end

-- Body filter phase handler
function _M.body_filter_phase_handler()
    local plugin_chain_header = ngx.req.get_headers()["X-Gateway-Body-Filter-Plugins"]
    if not plugin_chain_header then
        return
    end

    local plugin_names = {}
    for name in string.gmatch(plugin_chain_header, "([%w_%-%.]+)") do
        table.insert(plugin_names, name)
    end

    if #plugin_names > 0 then
        local ctx = {
            method = ngx.req.get_method(),
            uri = ngx.var.uri,
            chunk = ngx.arg[1],
            eof = ngx.arg[2],
            phase = "body_filter",
        }

        _M.execute_plugin_chain(plugin_names, ctx)

        -- Allow plugin to modify response body chunk
        if ctx.modified_chunk then
            ngx.arg[1] = ctx.modified_chunk
        end
    end
end

